mapper.select:
SELECT t.ID AS id, t.YEAR AS year, t.MAINTENANCE_UNIT_ID AS maintenanceUnitId, t.MAINTENANCE_UNIT_NAME AS maintenanceUnitName, t.COST_TYPE AS costType, d.DICT_LABEL AS costTypeName, t.AMOUNT AS amount, t.CREATE_BY AS createBy, t.CREATE_TIME AS createTime, t.UPDATE_BY AS updateBy, t.UPDATE_TIME AS updateTime, t.WARNING_USER_ID, t.WARNING_USER_NAME, t.WARNING_AMOUNT FROM E_COST_BUDGET_MANAGEMENT t LEFT JOIN M_DICT_DATA d ON d.DICT_TYPE = 'EXPENSE_TYPE' AND d.DICT_VALUE = t.COST_TYPE AND d.STATUS = '1' WHERE 1 = 1
AND t.YEAR = #{year}
AND t.COST_TYPE = #{costType}
ORDER BY t.YEAR DESC, t.CREATE_TIME DESC, t.ID DESC

SELECT COUNT(1)
FROM E_COST_BUDGET_MANAGEMENT t
WHERE t.YEAR = #{year}
AND t.MAINTENANCE_UNIT_ID = #{maintenanceUnitId}
AND t.COST_TYPE = #{costType}

    AND t.ID <> #{id}
